import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch35: CareerQuestion[] = [
  { id: "pta-b35-001", stem: "A PTA is treating a 42-year-old patient recently diagnosed with relapsing-remitting multiple sclerosis (RRMS) who reports worsening fatigue during afternoon therapy sessions. The patient's Expanded Disability Status Scale (EDSS) score is 3.5. The MOST appropriate modification to the treatment plan is:", options: ["Reduce exercise intensity and schedule sessions during the morning when fatigue is typically lower", "Discontinue all exercise until the patient reports no fatigue", "Schedule the patient exclusively for afternoon sessions to build tolerance to fatigue", "Increase exercise intensity to improve overall endurance and combat fatigue"], correctIndex: 0, rationale: "MS-related fatigue is one of the most common and disabling symptoms, often worsening with heat and later in the day. Scheduling sessions during cooler morning hours and reducing intensity helps manage fatigue without eliminating beneficial exercise. Discontinuing exercise would lead to deconditioning. Forcing afternoon sessions ignores circadian fatigue patterns. Increasing intensity may exacerbate symptoms and trigger a pseudo-exacerbation.", difficulty: 2, category: "Neurological Rehabilitation", topic: "MS Fatigue Management Strategies" },
  { id: "pta-b35-002", stem: "A PTA is working with a 68-year-old patient with Parkinson's disease who demonstrates a festinating gait pattern. The patient takes small, rapid, shuffling steps and appears to be chasing their center of gravity forward. Which intervention is MOST appropriate to address this gait deviation?", options: ["Verbal cueing to take large, exaggerated steps combined with visual floor markers placed at target stride lengths", "Instructing the patient to walk faster to improve momentum", "Having the patient walk only with a front-wheeled walker without any cueing strategies", "Placing ankle weights to slow down step frequency"], correctIndex: 0, rationale: "Festinating gait in Parkinson's disease responds well to external cueing strategies. Visual cues such as floor markers and verbal cues for large steps help override the basal ganglia dysfunction by using cortical (conscious) motor control pathways. Walking faster would worsen festination. A walker alone without cueing does not address the underlying motor programming deficit. Ankle weights add resistance but do not correct the step initiation problem.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Parkinson's Festinating Gait Cueing" },
  { id: "pta-b35-003", stem: "A PTA is treating a 55-year-old patient with benign paroxysmal positional vertigo (BPPV) affecting the right posterior semicircular canal. The patient reports intense vertigo and nystagmus when rolling to the right side in bed. Which repositioning maneuver is indicated?", options: ["The Dix-Hallpike test confirms the diagnosis but the Epley maneuver is not within PTA scope without PT direction", "The Epley (canalith repositioning) maneuver performed on the right side to move otoconia out of the posterior canal", "Brandt-Daroff habituation exercises performed bilaterally as the primary treatment", "The liberatory (Semont) maneuver performed on the left side"], correctIndex: 1, rationale: "For right posterior canal BPPV confirmed by a positive right Dix-Hallpike test, the Epley canalith repositioning maneuver is the gold standard treatment, performed on the affected (right) side to guide displaced otoconia out of the posterior semicircular canal into the utricle. Brandt-Daroff exercises are a secondary option if repositioning maneuvers fail. The Semont maneuver would need to be performed on the affected side, not the opposite side. The PTA may perform the Epley under the PT's plan of care.", difficulty: 2, category: "Neurological Rehabilitation", topic: "BPPV Canalith Repositioning" },
  { id: "pta-b35-004", stem: "A PTA is treating a 28-year-old patient who sustained a moderate traumatic brain injury (TBI) 3 weeks ago. The patient is at Rancho Los Amigos Level V (confused-inappropriate). During the treatment session, the patient becomes agitated and begins shouting. The PTA's BEST response is:", options: ["Continue the exercise program while speaking louder to redirect the patient's attention", "Reduce environmental stimulation by dimming lights, lowering noise, and using a calm, simple verbal approach", "Immediately discharge the patient from the session and document refusal to participate", "Apply physical restraints to prevent the patient from injuring themselves during the outburst"], correctIndex: 1, rationale: "At Rancho Level V, patients are confused and inappropriate with agitation. The best approach is to reduce environmental stimulation (dim lights, minimize noise, remove distractions) and use calm, simple verbal cues. This reduces sensory overload that triggers agitation. Speaking louder increases stimulation and worsens agitation. Discharging the patient misses an opportunity for therapeutic management. Physical restraints are a last resort and increase agitation in TBI patients.", difficulty: 2, category: "Neurological Rehabilitation", topic: "TBI Agitation Management Rancho Level V" },
  { id: "pta-b35-005", stem: "A PTA is treating a 72-year-old patient with MS who has significant spasticity in the bilateral lower extremities, particularly in the hip adductors and ankle plantarflexors. Which positioning strategy is MOST appropriate to manage spasticity during seated activities?", options: ["Position the patient in a wheelchair with hips and knees flexed to 90 degrees, feet flat on footrests, with an abduction wedge between the knees", "Allow the patient to sit with legs crossed to maintain a comfortable position", "Elevate both lower extremities on an extended leg rest with knees in full extension", "Position the patient in a reclined wheelchair with hips extended beyond 90 degrees"], correctIndex: 0, rationale: "Proper positioning is essential for spasticity management. Hip and knee flexion to 90 degrees with feet supported inhibits extensor spasticity patterns. An abduction wedge counteracts hip adductor spasticity. Crossing legs reinforces adductor spasticity. Extended knee positioning promotes extensor tone. A reclined position with hip extension facilitates the total extensor pattern. Neutral joint positioning and reflex-inhibiting postures are fundamental to spasticity management.", difficulty: 1, category: "Neurological Rehabilitation", topic: "Spasticity Positioning Strategies" },
  { id: "pta-b35-006", stem: "A PTA is performing gait training with a patient who had a left CVA resulting in right hemiplegia. The patient demonstrates circumduction of the right lower extremity during swing phase. This compensatory pattern is MOST likely caused by:", options: ["Inability to adequately dorsiflex the right ankle combined with difficulty flexing the right hip and knee during swing phase", "Excessive strength in the right hip flexors", "Weakness in the left (uninvolved) lower extremity", "Hyperactive stretch reflex in the right hip abductors"], correctIndex: 0, rationale: "Circumduction is a common compensatory gait pattern in hemiplegia where the patient swings the affected leg in a lateral arc. It compensates for inability to shorten the limb during swing phase due to weak or absent dorsiflexion (foot drop), inadequate knee flexion, and reduced hip flexion on the hemiplegic side. Excessive hip flexor strength would improve swing, not cause circumduction. Left leg weakness would affect stance, not right swing. Hip abductor hyperactivity would cause lateral deviation, not circumduction.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Hemiplegic Circumduction Gait Analysis" },
  { id: "pta-b35-007", stem: "A PTA is treating a 60-year-old patient with Parkinson's disease who reports increasing difficulty initiating movement from a seated position (start hesitation). The patient freezes when attempting to stand from a chair. Which strategy is MOST effective?", options: ["Have the patient rock forward and backward rhythmically in the chair before attempting to stand, using the momentum as an external cue to initiate the movement", "Instruct the patient to remain seated and call for assistance every time they need to stand", "Have the patient push straight up from the armrests without any preparatory movement", "Apply a posterior pelvic tilt before standing to activate the gluteal muscles"], correctIndex: 0, rationale: "Rhythmic rocking is an effective strategy for overcoming start hesitation (freezing) in Parkinson's disease. The rhythmic movement serves as an internal metronome that helps bypass the dysfunctional basal ganglia circuitry. It builds momentum and provides proprioceptive input that facilitates movement initiation. Calling for assistance promotes dependence. Pushing up without preparation does not address the freezing. Posterior pelvic tilt does not help initiate the sit-to-stand movement.", difficulty: 2, category: "Neurological Rehabilitation", topic: "Parkinson's Start Hesitation Strategies" },
  { id: "pta-b35-008", stem: "A PTA is treating a patient with a vestibular hypofunction following right vestibular neuritis. The patient reports oscillopsia (visual blurring with head movement). Which exercise is MOST appropriate to address this symptom?", options: ["Gaze stabilization exercises where the patient fixates on a stationary target while moving the head horizontally and vertically", "Canalith repositioning maneuvers performed three times daily", "Cervical isometric strengthening in a neutral head position", "Complete avoidance of all head movements until symptoms resolve"], correctIndex: 0, rationale: "Oscillopsia results from impaired vestibulo-ocular reflex (VOR). Gaze stabilization exercises (VOR x1 and x2) retrain the VOR by having the patient maintain visual fixation on a target while moving the head. This promotes vestibular compensation and neural adaptation. Canalith repositioning is for BPPV, not vestibular hypofunction. Cervical isometrics do not address VOR dysfunction. Avoiding head movement prevents the neural adaptation necessary for recovery and leads to prolonged disability.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Vestibular Gaze Stabilization Exercises" },
  { id: "pta-b35-009", stem: "A PTA is working with a 35-year-old patient with MS who is experiencing an acute exacerbation with new-onset optic neuritis and increased lower extremity weakness. The patient insists on continuing their regular high-intensity exercise program. The PTA should:", options: ["Continue the high-intensity program as the patient requests to maintain their fitness level", "Modify the program to low-intensity exercise with rest breaks, avoiding overheating, and monitor for symptom exacerbation", "Completely discontinue all physical therapy until the exacerbation fully resolves", "Switch entirely to aquatic therapy at 92°F water temperature"], correctIndex: 1, rationale: "During an MS exacerbation, exercise should be modified to lower intensity with rest breaks to prevent worsening of symptoms. Overheating (Uhthoff's phenomenon) can temporarily worsen neurological symptoms. Continuing high-intensity exercise risks exacerbating symptoms and prolonging recovery. Complete discontinuation leads to deconditioning. Aquatic therapy at 92°F is too warm for MS patients; water temperature should be 82-85°F to avoid heat sensitivity triggering symptom worsening.", difficulty: 3, category: "Neurological Rehabilitation", topic: "MS Acute Exacerbation Exercise Modification" },
  { id: "pta-b35-010", stem: "A PTA is treating a 50-year-old patient 6 weeks after a mild TBI who reports persistent dizziness, headache, and difficulty concentrating. The patient's symptoms worsen with physical exertion above a heart rate of 120 bpm. This presentation is MOST consistent with:", options: ["Post-concussion syndrome with autonomic dysfunction requiring a graded exercise protocol such as the Buffalo Concussion Treadmill Test approach", "Benign paroxysmal positional vertigo requiring canalith repositioning", "Cervicogenic headache requiring cervical manual therapy exclusively", "Complete recovery with malingering behavior"], correctIndex: 0, rationale: "Persistent symptoms beyond 4 weeks post-mild TBI with exertion-related symptom exacerbation suggests post-concussion syndrome with autonomic dysfunction. The Buffalo Concussion Treadmill Test helps identify the symptom threshold heart rate, and graded sub-threshold exercise progressively recalibrates autonomic function. BPPV presents with position-specific vertigo, not exertion-related symptoms. Cervicogenic headache is position-related. Labeling persistent post-concussion symptoms as malingering is inappropriate and unsupported.", difficulty: 3, category: "Neurological Rehabilitation", topic: "Post-Concussion Graded Exercise Protocol" },
  { id: "pta-b35-011", stem: "A PTA is treating a 45-year-old patient with MS who demonstrates bilateral intention tremor affecting the upper extremities during reaching tasks. Which adaptive strategy is MOST appropriate to improve functional reach accuracy?", options: ["Apply wrist weights of 1-2 pounds during functional tasks to dampen the tremor amplitude through increased limb inertia", "Instruct the patient to perform rapid ballistic reaching movements", "Eliminate all upper extremity activities and substitute with lower extremity exercises only", "Perform passive range of motion only without any active reaching"], correctIndex: 0, rationale: "Intention tremor in MS results from cerebellar dysfunction and worsens as the limb approaches a target. Light wrist weights (1-2 pounds) increase limb inertia, dampening oscillations and improving accuracy during functional tasks. Ballistic movements would worsen the tremor and reduce accuracy. Eliminating upper extremity activities leads to functional decline and neglects a primary rehabilitation goal. Passive ROM alone does not address functional tremor management or improve task performance.", difficulty: 3, category: "Neurological Rehabilitation", topic: "MS Intention Tremor Adaptive Strategies" },
  { id: "pta-b35-012", stem: "A PTA is treating a 70-year-old patient with Parkinson's disease who has a quiet, monotone voice (hypophonia) that makes communication difficult during therapy sessions. The MOST appropriate referral recommendation is:", options: ["Suggest the patient continue speaking normally as the voice will improve with medication adjustment alone", "Recommend referral to a speech-language pathologist for Lee Silverman Voice Treatment (LSVT LOUD) to address hypophonia", "Instruct the patient to whisper to conserve vocal energy", "Recommend the patient communicate exclusively through written notes"], correctIndex: 1, rationale: "Hypophonia is a common speech disorder in Parkinson's disease caused by reduced respiratory support and laryngeal muscle rigidity. LSVT LOUD is an evidence-based speech therapy program specifically designed for Parkinson's patients that focuses on increasing vocal loudness through intensive training. Medication alone often inadequately addresses speech deficits. Whispering further reduces vocal output. Written-only communication unnecessarily limits the patient's participation. The PTA should recognize when to recommend appropriate interdisciplinary referrals.", difficulty: 1, category: "Neurological Rehabilitation", topic: "Parkinson's Hypophonia Referral" },
  { id: "pta-b35-013", stem: "A PTA is treating a 65-year-old patient 6 weeks after a right total knee arthroplasty (TKA). The patient has achieved 0-95 degrees of knee ROM and reports anterior knee pain with stair climbing. The PTA should focus on:", options: ["Aggressive passive knee flexion stretching to achieve 130 degrees immediately", "Progressive quadriceps and hip strengthening with eccentric stair training, combined with patellar mobilization to address anterior knee pain", "Complete avoidance of all stair activities until pain resolves entirely", "Discontinuing therapy as the patient has achieved sufficient ROM for daily function"], correctIndex: 1, rationale: "At 6 weeks post-TKA, 95 degrees of flexion is progressing but still below the goal of 110-120 degrees. Anterior knee pain with stairs often results from patellar tracking issues and quadriceps weakness. Progressive quad and hip strengthening with eccentric stair training addresses the functional deficit while patellar mobilization improves patellar mechanics. Aggressive stretching risks tissue damage. Avoiding stairs prevents functional recovery. While 95 degrees allows basic function, continued therapy is needed to optimize outcomes.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "TKA Anterior Knee Pain Management" },
  { id: "pta-b35-014", stem: "A PTA is treating a 58-year-old patient 3 days after a left total hip arthroplasty (THA) performed via a posterior approach. During transfer training, the PTA observes the patient flexing the left hip beyond 90 degrees while reaching for shoes on the floor. The PTA should:", options: ["Allow the movement as reaching for shoes is a necessary functional activity", "Immediately stop the activity, educate the patient on posterior hip precautions including avoiding hip flexion beyond 90 degrees, adduction past midline, and internal rotation, and recommend adaptive equipment such as a long-handled shoe horn and sock aid", "Apply a hip abduction brace and continue the transfer training", "Document the incident but take no immediate action during the session"], correctIndex: 1, rationale: "Posterior approach THA precautions are critical to prevent dislocation: no hip flexion beyond 90 degrees, no adduction past midline, and no internal rotation. Reaching for shoes on the floor violates the flexion restriction. The PTA must immediately stop the activity, educate the patient on precautions, and recommend adaptive equipment (reacher, long-handled shoe horn, sock aid, elevated toilet seat). Allowing the movement risks dislocation. Simply applying a brace without education is insufficient. Documenting without intervening is negligent.", difficulty: 1, category: "Musculoskeletal Rehabilitation", topic: "Posterior THA Precaution Violation" },
  { id: "pta-b35-015", stem: "A PTA is treating a 30-year-old patient 4 months after anterior cruciate ligament (ACL) reconstruction using a bone-patellar tendon-bone autograft. The patient wants to return to competitive basketball. Which criterion-based assessment is MOST important before clearing for return to sport?", options: ["The patient can walk without a limp for 30 minutes continuously", "Limb symmetry index of greater than or equal to 90% on a battery of hop tests (single hop, triple hop, crossover hop, timed hop) along with quadriceps strength symmetry of at least 90% compared to the uninvolved side", "Full passive knee ROM has been achieved bilaterally", "The patient reports no pain during daily activities for one consecutive week"], correctIndex: 1, rationale: "Return-to-sport criteria after ACL reconstruction require objective functional testing. A limb symmetry index (LSI) of 90% or greater on hop tests demonstrates dynamic knee stability and confidence. Quadriceps strength symmetry of at least 90% reduces re-injury risk. Walking without a limp is a basic milestone, not a sport-readiness criterion. Full ROM is necessary but insufficient alone. Pain-free daily activities do not predict readiness for high-level sport demands. Evidence-based return-to-sport testing should include strength, hop performance, and sport-specific movement quality.", difficulty: 3, category: "Musculoskeletal Rehabilitation", topic: "ACL Return-to-Sport Criteria" },
  { id: "pta-b35-016", stem: "A PTA is treating a 45-year-old patient following arthroscopic rotator cuff repair (medium-sized supraspinatus tear). The surgeon's protocol indicates the patient is in Phase I (0-6 weeks post-op) with passive range of motion only. The patient demonstrates the ability to actively lift the arm and wants to begin active exercises. The PTA should:", options: ["Allow active range of motion since the patient can perform it without difficulty", "Follow the surgeon's protocol and continue with passive ROM only, educating the patient that active muscle contraction could stress the healing repair and potentially cause re-tear during the early protective phase", "Begin isometric strengthening exercises at this time since the patient is progressing well", "Advance the patient to resistive band exercises to capitalize on their motivation"], correctIndex: 1, rationale: "Phase I rotator cuff repair protocols restrict activity to passive ROM to protect the healing tendon. Active muscle contraction generates tensile forces on the repair site that could cause re-tear. The PTA must follow the surgeon's protocol even when the patient appears capable of more. Allowing active ROM, isometrics, or resistance exercises during the protective phase risks compromising the surgical repair. Patient education about the biological healing timeline is essential to ensure compliance with restrictions.", difficulty: 1, category: "Musculoskeletal Rehabilitation", topic: "Rotator Cuff Repair Phase I Protocol" },
  { id: "pta-b35-017", stem: "A PTA is treating a 52-year-old patient with adhesive capsulitis (frozen shoulder) in the frozen stage. The patient reports severe pain with passive stretching beyond the available range. The MOST appropriate treatment approach at this stage is:", options: ["Aggressive manipulation under anesthesia immediately", "Gentle joint mobilization within pain tolerance, modalities for pain management, and active-assisted ROM exercises to maintain available motion without forcing end-range stretching", "No treatment until the thawing stage begins spontaneously", "High-velocity thrust manipulation of the glenohumeral joint"], correctIndex: 1, rationale: "In the frozen stage of adhesive capsulitis, the capsule is fibrotic and highly painful at end range. Treatment focuses on pain management with modalities, gentle joint mobilization within tolerance, and active-assisted ROM to prevent further motion loss without forcing painful end-range stretching. Aggressive manipulation risks humeral fracture in osteoporotic patients or capsular rupture. Waiting without treatment allows continued stiffness. High-velocity thrust manipulation is contraindicated in the frozen stage due to the risk of tissue damage.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Adhesive Capsulitis Frozen Stage Treatment" },
  { id: "pta-b35-018", stem: "A PTA is treating a 40-year-old patient 8 weeks after open reduction internal fixation (ORIF) of a distal radius fracture. Radiographs confirm adequate healing, and the surgeon has cleared for progressive loading. The patient has limited wrist extension (35 degrees) and reduced grip strength. Which intervention combination is MOST appropriate?", options: ["Joint mobilization of the radiocarpal and midcarpal joints combined with progressive grip strengthening using therapeutic putty and wrist extension stretching", "Immobilization in a wrist splint for an additional 4 weeks before beginning any exercises", "Maximum resistance grip exercises immediately without addressing ROM limitations", "Ultrasound therapy exclusively without any exercise intervention"], correctIndex: 0, rationale: "At 8 weeks post-ORIF with surgical clearance, joint mobilization addresses capsular restrictions limiting wrist extension, therapeutic putty provides graded grip strengthening, and wrist extension stretching improves functional ROM. Continued immobilization at 8 weeks with confirmed healing delays recovery. Maximum resistance without addressing ROM limitations is inappropriate sequencing. Ultrasound alone without exercise does not restore function. A comprehensive approach addressing both ROM and strength deficits simultaneously optimizes recovery.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Distal Radius ORIF Progressive Loading" },
  { id: "pta-b35-019", stem: "A PTA is treating a 70-year-old patient with bilateral knee osteoarthritis who reports increased pain and swelling in the right knee after yesterday's therapy session that included open kinetic chain (OKC) knee extensions with 15 pounds of resistance. The MOST appropriate modification is:", options: ["Discontinue all lower extremity exercises permanently due to the pain response", "Switch to closed kinetic chain exercises such as partial squats and leg press at reduced loads, which distribute forces across multiple joints and reduce patellofemoral and tibiofemoral stress compared to heavy OKC knee extensions", "Continue the same OKC program but add ice afterward to manage the inflammation", "Increase resistance to 20 pounds to strengthen the quadriceps faster"], correctIndex: 1, rationale: "OKC knee extensions at heavy loads create significant tibiofemoral shear and patellofemoral compression forces, often aggravating osteoarthritis. CKC exercises (squats, leg press) distribute forces across the hip, knee, and ankle, reducing isolated joint stress while still strengthening the quadriceps. Discontinuing all exercise leads to deconditioning and worsening OA symptoms. Adding ice without modifying the aggravating exercise does not address the root cause. Increasing resistance would further exacerbate symptoms.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "OA CKC versus OKC Exercise Selection" },
  { id: "pta-b35-020", stem: "A PTA is treating a 22-year-old patient 12 weeks after surgical repair of a complete Achilles tendon rupture. The patient has been cleared for progressive strengthening. Which exercise progression is MOST appropriate?", options: ["Immediate plyometric jumping exercises to restore sport-specific function", "Bilateral heel raises progressing to single-leg heel raises, then eccentric heel drops from a step, gradually increasing load before introducing plyometric activities", "Running on a treadmill at maximum speed to test the repair", "Passive ankle dorsiflexion stretching beyond neutral to maximize ROM above all else"], correctIndex: 1, rationale: "Progressive loading after Achilles tendon repair follows a specific sequence: bilateral heel raises (reduced load per tendon), single-leg heel raises (full body weight loading), eccentric heel drops (controlled lengthening under load promotes tendon remodeling), and finally plyometrics. Jumping immediately at 12 weeks risks re-rupture of the healing tendon. Maximum speed running generates excessive forces before adequate tendon strength is restored. Aggressive dorsiflexion stretching may elongate the repair, reducing plantarflexion power and increasing re-rupture risk.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Achilles Repair Progressive Loading" },
  { id: "pta-b35-021", stem: "A PTA is treating a 55-year-old patient with lumbar spinal stenosis who reports bilateral lower extremity pain and heaviness that worsens with walking (neurogenic claudication) and improves with sitting or leaning forward. Which exercise position is MOST therapeutic?", options: ["Prone lumbar extension exercises to increase lordosis", "Exercises performed in a flexion-biased position such as posterior pelvic tilts, knee-to-chest stretches, and stationary cycling, which open the spinal canal and reduce neural compression", "High-impact aerobics on a hard surface to improve cardiovascular endurance", "Prolonged standing exercises to improve tolerance to upright postures"], correctIndex: 1, rationale: "Lumbar spinal stenosis narrows the spinal canal, compressing neural structures. Flexion-biased exercises (posterior pelvic tilts, knee-to-chest, cycling) open the spinal canal by reducing lumbar lordosis, decreasing neural compression and symptom relief. Extension exercises increase lordosis and further narrow the canal, worsening symptoms. High-impact aerobics on hard surfaces increase compressive loading. Prolonged standing maintains the lordotic posture that provokes symptoms. A flexion-based program is the cornerstone of conservative management.", difficulty: 1, category: "Musculoskeletal Rehabilitation", topic: "Spinal Stenosis Flexion-Biased Exercise" },
  { id: "pta-b35-022", stem: "A PTA is treating a 48-year-old patient 10 days after a left total shoulder arthroplasty (anatomic). The surgeon's protocol allows pendulum exercises and passive forward elevation to 120 degrees. During the session, the patient reports sharp pain at 100 degrees of passive forward elevation. The PTA should:", options: ["Push through the pain to reach the 120-degree protocol limit since the surgeon authorized it", "Stop at the point of sharp pain (100 degrees), document the limitation, and communicate this finding to the supervising PT and surgeon, as sharp pain may indicate a complication or the need for protocol modification", "Discontinue all passive ROM and immobilize the shoulder until the next surgeon visit", "Apply aggressive joint mobilization techniques to improve the range immediately"], correctIndex: 1, rationale: "Sharp pain during passive ROM post-arthroplasty may indicate prosthetic complications, excessive soft tissue tension, or healing concerns. The PTA should respect the pain response, stop at the onset of sharp pain, document findings, and communicate with the PT and surgeon. Pushing through sharp pain risks tissue damage or prosthetic issues. Complete immobilization without communication delays appropriate medical evaluation. Aggressive joint mobilization is contraindicated in the early post-surgical period and could damage the repair.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Total Shoulder Arthroplasty Pain Response" },
  { id: "pta-b35-023", stem: "A PTA is treating a 60-year-old patient with lateral epicondylalgia (tennis elbow) who has failed 8 weeks of traditional physical therapy. The patient continues to report pain with gripping and wrist extension. Which advanced intervention approach has the STRONGEST evidence for chronic lateral epicondylalgia?", options: ["Continued use of high-dose anti-inflammatory medications indefinitely", "An eccentric wrist extensor strengthening program progressing to heavy slow resistance training, which promotes tendon remodeling and collagen organization", "Complete rest and immobilization for an additional 8 weeks", "Ultrasound therapy three times weekly as the sole intervention"], correctIndex: 1, rationale: "Chronic lateral epicondylalgia (tendinopathy) involves collagen disorganization and failed healing rather than acute inflammation. Eccentric loading and heavy slow resistance training stimulate mechanotransduction, promote collagen synthesis and alignment, and improve tendon structure. Long-term NSAID use masks symptoms without addressing the tendon pathology and carries GI and cardiovascular risks. Complete rest leads to further tendon degeneration. Ultrasound alone has limited evidence for tendinopathy as a standalone treatment.", difficulty: 3, category: "Musculoskeletal Rehabilitation", topic: "Lateral Epicondylalgia Eccentric Loading" },
  { id: "pta-b35-024", stem: "A PTA is treating a 35-year-old patient 6 months after ACL reconstruction who is performing single-leg squats. The patient demonstrates dynamic knee valgus (knee collapsing medially). Which muscle group should the PTA prioritize strengthening to correct this movement pattern?", options: ["Ankle plantarflexors to improve push-off power", "Hip external rotators and abductors, particularly the gluteus medius, to control femoral internal rotation and adduction that contributes to dynamic knee valgus", "Knee flexors (hamstrings) exclusively to improve posterior stability", "Lumbar paraspinal extensors to improve trunk posture"], correctIndex: 1, rationale: "Dynamic knee valgus results primarily from inadequate hip external rotation and abduction control. The gluteus medius controls femoral internal rotation and adduction during single-leg stance. Weakness allows the femur to internally rotate and adduct, driving the knee into valgus. Ankle plantarflexors do not control frontal or transverse plane knee mechanics. Hamstrings provide posterior knee stability but do not directly address valgus. Paraspinal extensors affect trunk posture but are not the primary contributor to knee valgus during single-leg activities.", difficulty: 2, category: "Musculoskeletal Rehabilitation", topic: "Dynamic Knee Valgus Hip Strengthening" },
  { id: "pta-b35-025", stem: "A PTA is designing a plyometric training program for a 25-year-old athlete recovering from a lower extremity injury. The patient has achieved full ROM and strength symmetry. Which plyometric exercise progression is MOST appropriate?", options: ["Begin with depth jumps from a 36-inch box as the starting exercise", "Progress from double-leg low-intensity exercises (squat jumps in place) to single-leg activities (single-leg hops), then to high-intensity exercises (depth jumps and bounding) with adequate recovery between sets", "Start with single-leg bounding on day one to maximize sport specificity", "Perform plyometric exercises daily without rest days to accelerate adaptation"], correctIndex: 1, rationale: "Plyometric progression follows a systematic approach: double-leg before single-leg, low-intensity before high-intensity, stable surfaces before unstable surfaces. Starting with squat jumps builds eccentric loading tolerance before advancing to single-leg hops and high-intensity depth jumps. Starting with depth jumps or single-leg bounding without foundational exercises risks injury due to excessive eccentric forces. Daily plyometrics without rest days prevents recovery and adaptation, increasing overuse injury risk. Adequate 48-72 hour recovery between sessions is recommended.", difficulty: 2, category: "Therapeutic Exercise", topic: "Plyometric Training Progression" },
  { id: "pta-b35-026", stem: "A PTA is implementing a progressive overload strengthening program for a 50-year-old patient recovering from a total knee replacement. The patient has been performing straight leg raises with 3 pounds of ankle weight for 3 sets of 15 repetitions without difficulty for the past 2 weeks. To apply the principle of progressive overload, the PTA should:", options: ["Continue the same exercise at the same intensity since the patient is comfortable", "Increase the ankle weight to 5 pounds while maintaining 3 sets of 10-12 repetitions, or progress to a more challenging exercise such as mini-squats, to provide a new stimulus for continued strength gains", "Remove the ankle weight and increase repetitions to 50 per set", "Switch entirely to passive range of motion exercises"], correctIndex: 1, rationale: "Progressive overload requires systematically increasing the demand on the musculoskeletal system to drive continued adaptation. When an exercise becomes easy (3x15 without difficulty), load should be increased (5 pounds) with temporary repetition reduction (10-12) or the exercise should be progressed to a more challenging variation. Continuing the same load provides no new stimulus (maintenance, not progression). Removing weight and increasing reps to 50 shifts to endurance training without building strength. Switching to passive ROM is a regression.", difficulty: 1, category: "Therapeutic Exercise", topic: "Progressive Overload Principle Application" },
  { id: "pta-b35-027", stem: "A PTA is designing a core stabilization program for a 38-year-old patient with chronic low back pain. The patient is in the initial phase of stabilization training. Which exercise is MOST appropriate to begin with?", options: ["Supine drawing-in maneuver (abdominal hollowing) with isolated transversus abdominis activation, progressing to maintaining the contraction during limb movements", "Full sit-ups with hands behind the head for maximum abdominal activation", "Heavy barbell deadlifts to strengthen the entire posterior chain", "Russian twists with a 20-pound medicine ball for rotational core strength"], correctIndex: 0, rationale: "Core stabilization progresses through phases: local stabilization (deep muscle activation), then global stabilization (integration with larger muscles), then dynamic stabilization (functional movements under load). The drawing-in maneuver isolates the transversus abdominis, the deepest core stabilizer, establishing a foundation for all subsequent progressions. Full sit-ups primarily activate the rectus abdominis without training deep stabilizers and increase spinal flexion loading. Heavy deadlifts and weighted Russian twists are advanced exercises inappropriate for the initial stabilization phase.", difficulty: 1, category: "Therapeutic Exercise", topic: "Core Stabilization Initial Phase" },
  { id: "pta-b35-028", stem: "A PTA is treating a 62-year-old patient with type 2 diabetes and peripheral neuropathy who wants to improve cardiovascular fitness. The patient has reduced sensation in both feet and a history of foot ulcers. Which aerobic exercise is MOST appropriate?", options: ["Long-distance running on pavement to maximize caloric expenditure", "Recumbent cycling or swimming, which provide cardiovascular benefits while minimizing repetitive plantar pressure and reducing the risk of foot ulceration in a patient with neuropathy", "High-impact step aerobics to improve bone density simultaneously", "Prolonged treadmill walking in bare feet to improve proprioception"], correctIndex: 1, rationale: "Patients with diabetic neuropathy and a history of foot ulcers require non-weight-bearing or reduced-impact aerobic exercise to minimize plantar pressure and ulceration risk. Recumbent cycling and swimming provide excellent cardiovascular conditioning without repetitive foot loading. Long-distance running generates high repetitive plantar forces. Step aerobics involves impact and stepping that increases ulcer risk. Barefoot treadmill walking removes protective footwear from insensate feet, dramatically increasing injury and ulceration risk.", difficulty: 2, category: "Therapeutic Exercise", topic: "Diabetic Neuropathy Aerobic Exercise Selection" },
  { id: "pta-b35-029", stem: "A PTA is implementing a balance training program for a 75-year-old patient with a history of falls. The patient can maintain standing balance on a firm surface with eyes open for 30 seconds but loses balance immediately when standing on foam with eyes closed. Which progression is MOST appropriate?", options: ["Skip directly to advanced balance activities on an unstable surface with eyes closed since the patient needs the most challenging exercises", "Progress systematically by challenging one sensory system at a time: firm surface with eyes closed, then foam surface with eyes open, before combining both challenges (foam with eyes closed)", "Only practice balance on firm surfaces with eyes open indefinitely since the patient is safe in that condition", "Use a wheelchair exclusively to eliminate all fall risk during balance training"], correctIndex: 1, rationale: "Balance training should follow a systematic progression that challenges sensory systems one at a time before combining them. Standing on firm surface with eyes closed removes visual input. Foam with eyes open challenges somatosensory input. Combining both (foam with eyes closed) is the most challenging condition, relying heavily on vestibular input. Skipping to the most difficult condition without building foundational skills risks falls during training. Staying only at the easiest level does not promote adaptation. Using a wheelchair eliminates the therapeutic benefit of balance training.", difficulty: 1, category: "Therapeutic Exercise", topic: "Sensory Balance Training Progression" },
  { id: "pta-b35-030", stem: "A PTA is working with a 20-year-old collegiate volleyball player on a shoulder injury prevention program. Which exercise combination BEST addresses the common shoulder injury mechanisms in overhead athletes?", options: ["Isolated biceps curls and chest press exercises to build overall arm strength", "Scapular stabilization exercises (serratus anterior activation, lower trapezius strengthening) combined with rotator cuff eccentric strengthening in sport-specific overhead positions", "Passive stretching of the shoulder into maximum external rotation only", "Upper trapezius shrugs and deltoid raises exclusively"], correctIndex: 1, rationale: "Overhead athletes are at risk for subacromial impingement, labral tears, and rotator cuff injuries due to scapular dyskinesis and rotator cuff fatigue. Scapular stabilization (serratus anterior, lower trapezius) ensures proper scapulohumeral rhythm during overhead movements. Eccentric rotator cuff strengthening in overhead positions prepares the cuff for the deceleration demands of throwing and spiking. Biceps curls and chest press do not address sport-specific mechanisms. Maximum external rotation stretching alone risks anterior instability. Upper trap and deltoid exercises may worsen scapular dyskinesis by reinforcing imbalanced muscle patterns.", difficulty: 3, category: "Therapeutic Exercise", topic: "Overhead Athlete Shoulder Prevention" },
  { id: "pta-b35-031", stem: "A PTA is training a patient to perform Nordic hamstring curls as part of an injury prevention program. During the exercise, the patient should:", options: ["Lean forward from the knees as slowly as possible, using the hamstrings to eccentrically control the descent, then catch themselves with their hands and push back up to the starting position", "Rapidly drop forward and rely on the quadriceps to control the movement", "Perform the exercise concentrically only by pulling themselves back up without controlling the descent", "Flex the hips throughout the movement to reduce hamstring demand"], correctIndex: 0, rationale: "Nordic hamstring curls are the gold-standard eccentric hamstring exercise for hamstring strain prevention. The athlete kneels with feet anchored and leans forward as slowly as possible, eccentrically loading the hamstrings at long muscle lengths. Hands catch the body at the bottom. The eccentric phase is the therapeutic component. Rapid dropping eliminates the eccentric training effect. The quadriceps are not the target muscle. Concentric-only training misses the eccentric adaptation that prevents injury. Hip flexion reduces hamstring length and loading, negating the exercise purpose.", difficulty: 2, category: "Therapeutic Exercise", topic: "Nordic Hamstring Curl Technique" },
  { id: "pta-b35-032", stem: "A PTA is implementing a neuromuscular electrical stimulation (NMES) program to improve quadriceps activation in a patient 2 weeks after ACL reconstruction. The patient has significant quadriceps inhibition (arthrogenic muscle inhibition). Which NMES parameters are MOST appropriate?", options: ["Frequency of 2 Hz with a continuous duty cycle for passive relaxation", "Frequency of 50-75 Hz with a duty cycle of 10 seconds on/50 seconds off, combined with voluntary quadriceps contraction during the stimulation on-time", "Frequency of 1 Hz with 1 second on/1 second off to produce individual twitches", "Sensory-level stimulation only at sub-motor threshold intensity"], correctIndex: 1, rationale: "NMES for quadriceps re-education post-ACL reconstruction requires frequencies of 50-75 Hz to produce a tetanic (fused) muscle contraction, combined with voluntary contraction effort to maximize motor unit recruitment. A 10-second on/50-second off duty cycle allows adequate recovery between contractions. Low frequencies (1-2 Hz) produce individual twitches insufficient for strengthening. Continuous stimulation causes rapid fatigue. Sensory-level stimulation does not produce muscle contraction and cannot overcome arthrogenic inhibition. The combination of NMES with voluntary effort is superior to either alone.", difficulty: 3, category: "Therapeutic Exercise", topic: "NMES Quadriceps Reactivation Post-ACL" },
  { id: "pta-b35-033", stem: "A PTA is applying aquatic exercise principles for a patient with severe lower extremity osteoarthritis. When the patient is immersed to the level of the xiphoid process, approximately what percentage of body weight is offloaded?", options: ["Approximately 10% of body weight is offloaded", "Approximately 25% of body weight is offloaded", "Approximately 40% of body weight is offloaded", "Approximately 60% of body weight is offloaded"], correctIndex: 3, rationale: "Buoyancy principles dictate that immersion to the xiphoid process (chest level) offloads approximately 60% of body weight, significantly reducing joint loading for patients with arthritis. Immersion to the ASIS (waist level) offloads approximately 50%, and immersion to the C7 spinous process (neck level) offloads approximately 90%. These percentages guide exercise prescription by controlling the amount of weight-bearing during aquatic therapy. Understanding buoyancy principles allows the PTA to precisely control joint loading based on the patient's tolerance and therapeutic goals.", difficulty: 2, category: "Therapeutic Exercise", topic: "Aquatic Therapy Buoyancy Weight Offloading" },
  { id: "pta-b35-034", stem: "A PTA is treating a 45-year-old patient with chronic lateral ankle instability. The patient performs single-leg stance on a foam surface with eyes open. To further progress proprioceptive training, the PTA should NEXT:", options: ["Return to double-leg stance on a firm surface as the final progression", "Progress to single-leg stance on a foam surface with eyes closed, then advance to dynamic perturbation training and sport-specific agility drills on unstable surfaces", "Have the patient use bilateral upper extremity support on parallel bars indefinitely", "Discontinue proprioceptive training since the patient can stand on foam"], correctIndex: 1, rationale: "Proprioceptive training progression for ankle instability follows increasing challenge: single-leg foam with eyes closed removes visual input, forcing reliance on somatosensory and vestibular systems. Dynamic perturbation training adds reactive balance demands. Sport-specific agility drills on unstable surfaces provide the highest level of functional proprioceptive challenge. Returning to double-leg firm surface is regression. Bilateral support eliminates the balance challenge. Discontinuing training at an intermediate level prevents achievement of full functional stability needed for activity demands.", difficulty: 2, category: "Therapeutic Exercise", topic: "Ankle Proprioceptive Training Progression" },
  { id: "pta-b35-035", stem: "A PTA is applying cold laser (low-level laser therapy/photobiomodulation) to a patient's Achilles tendon for chronic tendinopathy. Which statement about cold laser therapy is MOST accurate?", options: ["Cold laser produces thermal tissue heating similar to ultrasound and should be monitored for temperature changes", "Cold laser works through photobiomodulation by stimulating mitochondrial cytochrome c oxidase, increasing ATP production and cellular metabolism to promote tissue healing without producing significant thermal effects", "Cold laser is contraindicated for all musculoskeletal conditions and is only approved for wound healing", "Cold laser penetrates to the same depth regardless of wavelength selection"], correctIndex: 1, rationale: "Cold laser (photobiomodulation) produces non-thermal effects by stimulating cytochrome c oxidase in mitochondria, enhancing ATP production, cellular metabolism, and tissue repair. Unlike therapeutic ultrasound, it does not produce significant tissue heating. Cold laser is used for various musculoskeletal conditions including tendinopathy, not limited to wound healing. Wavelength significantly affects penetration depth: longer wavelengths (near-infrared 800-1000nm) penetrate deeper than shorter wavelengths (red light 600-700nm), which is important for treating deep structures like tendons.", difficulty: 2, category: "Therapeutic Modalities", topic: "Cold Laser Photobiomodulation Mechanism" },
  { id: "pta-b35-036", stem: "A PTA is applying cryotherapy using an ice pack to a patient's acutely sprained ankle. The MINIMUM recommended duration for effective cryotherapy to achieve tissue temperature reduction sufficient for pain relief and reduced inflammation is:", options: ["2-3 minutes of application for maximum benefit", "10-20 minutes of application with a barrier (towel) between the ice pack and skin to allow adequate tissue cooling while protecting against cryotherapy burns", "45-60 minutes of continuous application for optimal results", "5 seconds of ice application followed by immediate removal"], correctIndex: 1, rationale: "Effective cryotherapy requires 10-20 minutes to sufficiently lower tissue temperature for therapeutic benefit (pain relief, reduced nerve conduction velocity, decreased metabolic rate, vasoconstriction reducing edema). A barrier protects against cryotherapy burns and frostbite. Application of 2-3 minutes or 5 seconds is insufficient to achieve meaningful tissue cooling. Application exceeding 20-30 minutes risks tissue damage, frostbite, and paradoxical vasodilation (hunting response). The PTA should monitor skin response throughout and remove the ice if excessive blanching or numbness occurs.", difficulty: 1, category: "Therapeutic Modalities", topic: "Cryotherapy Application Duration" },
  { id: "pta-b35-037", stem: "A PTA is considering using cervical mechanical traction for a patient with cervical radiculopathy. Which of the following is an ABSOLUTE contraindication to cervical traction?", options: ["Mild cervical muscle spasm without neurological involvement", "Ligamentous instability of the cervical spine, such as in patients with rheumatoid arthritis affecting the atlantoaxial joint or Down syndrome with atlantoaxial instability", "Subacute cervical disc herniation without cord compression", "Mild osteoarthritis of the cervical facet joints"], correctIndex: 1, rationale: "Ligamentous instability of the cervical spine is an absolute contraindication to cervical traction. Patients with rheumatoid arthritis affecting the atlantoaxial joint or Down syndrome with atlantoaxial instability have compromised ligamentous support; traction forces could cause spinal cord compression or vertebral subluxation. Mild muscle spasm is actually an indication for traction. Subacute disc herniation without cord compression may benefit from traction. Mild facet OA is not a contraindication. Other absolute contraindications include untreated spinal cord compression, vertebral artery insufficiency, and recent cervical fracture.", difficulty: 2, category: "Therapeutic Modalities", topic: "Cervical Traction Contraindications" },
  { id: "pta-b35-038", stem: "A PTA is applying intermittent pneumatic compression (IPC) to a patient's lower extremity to manage lymphedema. The compression pressure should be set:", options: ["Above the patient's diastolic blood pressure to maximize fluid displacement from the limb", "Between 30-60 mmHg, which is sufficient to promote lymphatic drainage without exceeding capillary filtration pressure and risking tissue damage", "At 200 mmHg for maximum effectiveness in reducing swelling", "At the same pressure as a blood pressure cuff during systolic measurement"], correctIndex: 1, rationale: "IPC for lymphedema uses pressures of 30-60 mmHg, which effectively promote lymphatic and venous return without causing tissue damage or exceeding capillary filtration pressure. Pressures above diastolic or at 200 mmHg risk tissue ischemia, capillary damage, and pain. Excessive pressures can damage lymphatic vessels and worsen lymphedema. Blood pressure cuff pressure during systolic measurement (typically 120+ mmHg) would be excessive. The PTA should also ensure proper limb positioning (elevated), sequential inflation from distal to proximal, and appropriate treatment duration (30-60 minutes).", difficulty: 2, category: "Therapeutic Modalities", topic: "Intermittent Pneumatic Compression Parameters" },
  { id: "pta-b35-039", stem: "A PTA is applying therapeutic ultrasound to a patient's lateral epicondyle for chronic tendinopathy. The treatment area is approximately 2 times the size of the transducer's effective radiating area (ERA). The appropriate technique for this treatment area size is:", options: ["Hold the transducer stationary over the area for the entire treatment duration", "Move the transducer in slow, overlapping circular or longitudinal strokes at a speed of approximately 4 cm/second, covering the treatment area that is up to 2 times the ERA, which is the maximum recommended treatment area per application site", "Move the transducer as rapidly as possible across the entire forearm", "Apply the transducer with firm pressure without any coupling medium"], correctIndex: 1, rationale: "Therapeutic ultrasound application requires the treatment area to be no more than 2 times the ERA for effective energy delivery. The transducer must move continuously at approximately 4 cm/second in overlapping strokes to ensure even energy distribution and prevent hot spots. Stationary application causes standing waves and periosteal burns. Rapid movement over a large area dilutes energy below therapeutic thresholds. A coupling medium (gel or water) is essential for sound wave transmission; without it, air reflects the ultrasound waves preventing tissue penetration.", difficulty: 2, category: "Therapeutic Modalities", topic: "Therapeutic Ultrasound Technique" },
  { id: "pta-b35-040", stem: "A PTA is applying moist heat to a patient's lumbar paraspinal muscles before manual stretching. Which of the following BEST describes the physiological effects of moist heat application?", options: ["Decreased blood flow, increased muscle tone, and reduced nerve conduction velocity", "Increased collagen extensibility, increased blood flow, decreased muscle guarding, and increased tissue metabolism, which collectively prepare the tissue for more effective stretching", "Decreased collagen extensibility and increased tissue stiffness for joint protection", "No measurable physiological effects; moist heat provides only psychological comfort"], correctIndex: 1, rationale: "Moist heat therapy produces several physiological effects: increased collagen extensibility (allows greater tissue elongation during stretching), increased local blood flow (vasodilation improves oxygen and nutrient delivery), decreased muscle guarding (reduced gamma motor neuron activity), and increased tissue metabolism. These effects collectively make tissues more amenable to stretching. Heat increases (not decreases) blood flow. It increases (not decreases) collagen extensibility. Moist heat has well-documented measurable physiological effects beyond psychological comfort. Moist heat is preferred over dry heat due to superior heat transfer properties.", difficulty: 1, category: "Therapeutic Modalities", topic: "Moist Heat Physiological Effects" },
  { id: "pta-b35-041", stem: "A PTA is applying iontophoresis using dexamethasone to a patient's plantar fascia for inflammation. Which electrode setup is correct for driving dexamethasone (a negatively charged ion) into the tissue?", options: ["Place dexamethasone under the positive electrode (anode) since opposite charges attract", "Place dexamethasone under the negative electrode (cathode) since like charges repel, driving the negatively charged dexamethasone away from the electrode and into the tissue", "Electrode polarity does not matter for iontophoresis drug delivery", "Place the medication midway between both electrodes for equal distribution"], correctIndex: 1, rationale: "Iontophoresis uses electrical current to drive charged medications into tissue. The fundamental principle is that like charges repel: negatively charged ions (dexamethasone phosphate is negative) are placed under the negative electrode (cathode), where the negative charge repels the medication into the tissue. Placing it under the positive electrode would attract the medication toward the electrode rather than into the tissue. Polarity is critical for effective drug delivery. Placing medication between electrodes provides no driving force for tissue penetration. The PTA must know the polarity of common iontophoresis medications.", difficulty: 3, category: "Therapeutic Modalities", topic: "Iontophoresis Electrode Polarity" },
  { id: "pta-b35-042", stem: "A PTA is treating a patient with myofascial trigger points in the upper trapezius using electrical stimulation. Which waveform and parameter combination is MOST appropriate for trigger point release?", options: ["High-voltage pulsed current at motor-level intensity with the active electrode placed directly over the trigger point to produce rhythmic muscle contraction and fatigue the trigger point", "Interferential current at sensory level only for 5 minutes", "Direct current (galvanic) at maximum intensity for continuous muscle contraction", "Microcurrent at sub-sensory level for 2 minutes"], correctIndex: 0, rationale: "High-voltage pulsed current (HVPC) at motor-level intensity produces tetanic muscle contraction at the trigger point, fatiguing the sustained sarcomere contraction that characterizes the trigger point. The rhythmic contraction-relaxation cycle promotes local blood flow, metabolic waste removal, and sarcomere reset. Interferential at sensory level provides pain modulation but does not address the contractile component. Direct current at maximum intensity risks chemical burns. Microcurrent at sub-sensory level for 2 minutes provides insufficient stimulus for trigger point deactivation.", difficulty: 3, category: "Therapeutic Modalities", topic: "Trigger Point Electrical Stimulation" },
  { id: "pta-b35-043", stem: "A PTA is applying a fluidotherapy treatment to a patient's hand for stiffness after a distal radius fracture. An advantage of fluidotherapy over a paraffin bath for hand treatment is:", options: ["Fluidotherapy provides deeper heating than any other thermal modality", "Fluidotherapy allows the patient to perform active exercises during the treatment while receiving dry heat, combining thermal effects with simultaneous ROM activities", "Fluidotherapy is a cold modality that reduces inflammation more effectively than cryotherapy", "Fluidotherapy requires no temperature monitoring during treatment"], correctIndex: 1, rationale: "Fluidotherapy uses heated cellulose particles suspended in air to provide dry heat. Its primary advantage over paraffin is that patients can actively exercise the hand during treatment, combining thermal benefits (increased collagen extensibility, pain relief) with simultaneous ROM exercises. Fluidotherapy is a superficial heat modality, not deeper than all others. It is a heat modality, not cold. All thermal modalities require temperature monitoring for safety. The ability to exercise during treatment makes fluidotherapy particularly effective for post-fracture hand stiffness where both heat and motion are therapeutic goals.", difficulty: 1, category: "Therapeutic Modalities", topic: "Fluidotherapy vs Paraffin Advantages" },
  { id: "pta-b35-044", stem: "A PTA is applying mechanical lumbar traction to a patient with a confirmed L4-L5 disc herniation causing left L5 radiculopathy. For the initial treatment, the traction force should be approximately:", options: ["100% of the patient's body weight for maximum disc distraction", "25-50% of the patient's body weight, starting at the lower end to assess tolerance before progressively increasing force in subsequent sessions", "5 pounds regardless of patient body weight", "Equal to the patient's body weight plus an additional 50 pounds"], correctIndex: 1, rationale: "Lumbar traction for disc herniation typically requires 25-50% of body weight to achieve meaningful disc distraction and separation. Initial sessions start at the lower end (25%) to assess patient tolerance before progressing. Forces of 100% or more of body weight are excessive and risk injury. Five pounds is insufficient to overcome soft tissue resistance and achieve lumbar distraction. Forces exceeding body weight risk muscle spasm, tissue injury, and are unnecessary for therapeutic benefit. The PTA should monitor for symptom centralization or peripheralization during traction to guide treatment effectiveness.", difficulty: 2, category: "Therapeutic Modalities", topic: "Lumbar Traction Force Parameters" },
  { id: "pta-b35-045", stem: "A PTA is performing a stand-pivot transfer with a 200-pound patient who has right-sided hemiplegia from the bed to a wheelchair. The wheelchair should be positioned:", options: ["On the patient's right (affected) side so the patient pivots toward the affected side", "On the patient's left (unaffected) side at approximately a 45-degree angle to the bed, allowing the patient to lead with the stronger left leg and pivot toward the wheelchair", "Directly behind the patient requiring a 180-degree turn", "Six feet away from the bed to allow adequate walking distance"], correctIndex: 1, rationale: "For hemiplegic patients, the wheelchair should be positioned on the unaffected (stronger) side so the patient leads with the stronger leg and pivots toward the wheelchair using the stronger side for stability and control. Placing it on the affected side forces the patient to lead with the weak leg and bear weight on the affected side during pivoting, increasing fall risk. A 180-degree turn is unnecessarily complex and increases fall risk. Placing the wheelchair far away requires ambulation, not a transfer. The 45-degree angle minimizes the pivot arc.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Hemiplegic Transfer Wheelchair Positioning" },
  { id: "pta-b35-046", stem: "A PTA is treating a patient in an isolation room who is on contact precautions for methicillin-resistant Staphylococcus aureus (MRSA). The PTA plans to use a therapy ball and theraband during the session. After the session, the PTA should:", options: ["Return the equipment to the general equipment storage area after wiping it with a dry cloth", "Clean all equipment with hospital-approved disinfectant before removing it from the room, or dedicate the equipment to that patient's room for the duration of isolation, and perform hand hygiene after removing gloves and gown", "Only wash hands; equipment cleaning is the housekeeping department's responsibility", "Spray the equipment with water and allow it to air dry in the hallway"], correctIndex: 1, rationale: "Contact precautions for MRSA require that all equipment either be dedicated to the patient's room or thoroughly disinfected with hospital-approved disinfectant before removal. MRSA can survive on surfaces for days to weeks. Wiping with a dry cloth does not kill MRSA. The PTA is responsible for cleaning therapy equipment, not housekeeping. Water alone does not provide adequate disinfection. Proper hand hygiene after removing PPE is also essential. The PTA should don appropriate PPE (gown and gloves) before entering and remove it properly before leaving the room.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "MRSA Contact Precaution Equipment" },
  { id: "pta-b35-047", stem: "A PTA is treating an 80-year-old patient who is at high fall risk. The patient's medications include furosemide (loop diuretic), metoprolol (beta-blocker), and alprazolam (benzodiazepine). Which medication-related factor poses the GREATEST fall risk?", options: ["Furosemide because it may cause nocturia requiring frequent bathroom trips", "Metoprolol because it prevents compensatory heart rate increase during position changes", "Alprazolam because benzodiazepines cause sedation, impaired balance, cognitive dulling, and slowed reaction time, representing the strongest independent medication-related fall risk factor in the elderly", "None of these medications affect fall risk in the elderly"], correctIndex: 2, rationale: "While all three medications contribute to fall risk, benzodiazepines (alprazolam) represent the strongest independent medication-related fall risk factor in the elderly. They cause sedation, impaired balance and coordination, cognitive dulling, and slowed reaction time. Furosemide causes orthostatic hypotension and frequent urination, contributing to fall risk. Metoprolol blunts heart rate response to position changes. However, the Beers Criteria identifies benzodiazepines as potentially inappropriate medications for older adults specifically due to fall and fracture risk. All three medications together create a compounded risk.", difficulty: 3, category: "Patient Safety & Body Mechanics", topic: "Benzodiazepine Fall Risk in Elderly" },
  { id: "pta-b35-048", stem: "A PTA is performing a two-person dependent lift transfer of a 250-pound patient from bed to wheelchair. To protect their own body mechanics, the PTAs should:", options: ["Bend at the waist and use their back muscles to lift the patient as high as possible", "Maintain a wide base of support, keep the patient close to their bodies, bend at the hips and knees (not the waist), engage core muscles, coordinate the lift with a verbal count, and avoid twisting during the transfer", "Lift the patient rapidly to minimize the time under load", "Stand with feet together for a stable narrow base and lean backward to counterbalance the patient's weight"], correctIndex: 1, rationale: "Proper body mechanics for a two-person dependent lift: wide base of support for stability, keeping the load close to the body to minimize torque on the spine, bending at the hips and knees to use the large leg muscles rather than the back, core engagement to protect the lumbar spine, verbal count coordination to synchronize effort, and no twisting (pivoting with the feet instead). Bending at the waist loads the lumbar spine. Rapid lifting eliminates control. Narrow base reduces stability. Leaning backward shifts the load to the lumbar spine. Proper body mechanics prevent healthcare worker injuries.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Two-Person Lift Body Mechanics" },
  { id: "pta-b35-049", stem: "A PTA is treating a patient who begins to have a seizure during a therapy session. The patient is on a treatment mat on the floor. The PTA's FIRST action should be:", options: ["Insert a bite block or tongue depressor between the patient's teeth to prevent tongue biting", "Clear the area of hazardous objects, protect the patient's head with a folded towel, turn the patient on their side if possible, time the seizure duration, and do NOT restrain or place anything in the patient's mouth", "Immediately attempt to perform CPR", "Leave the patient alone and go call 911 from the front desk"], correctIndex: 1, rationale: "Current seizure first aid: clear surrounding hazards, protect the head from injury, position on the side (recovery position) if possible to maintain airway and prevent aspiration, time the seizure, and never restrain the patient or put anything in their mouth. Bite blocks and tongue depressors are contraindicated as they can break teeth, lacerate oral tissues, or obstruct the airway. CPR is not indicated unless the patient stops breathing after the seizure. The PTA should stay with the patient and have someone else call for help. Seizures lasting more than 5 minutes or repeated seizures require emergency medical services.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Seizure First Aid During Therapy" },
  { id: "pta-b35-050", stem: "A PTA is training a patient to use a standard walker for ambulation. The patient has been instructed to advance the walker, then step with the weaker leg, then step with the stronger leg. The patient demonstrates placing the walker too far forward (approximately 24 inches ahead). This distance is problematic because:", options: ["Placing the walker too far forward shifts the patient's center of gravity anterior to the base of support, increasing the risk of forward falls and making it harder to maintain an upright posture", "The walker is designed to be placed as far forward as possible for maximum step length", "A 24-inch walker advance is within the normal recommended range and requires no correction", "Placing the walker far forward reduces the work on the upper extremities"], correctIndex: 0, rationale: "The recommended walker advance distance is approximately one arm's length or 6-12 inches forward. Advancing the walker too far (24 inches) forces the patient to lean forward excessively, shifting the center of gravity anterior to the base of support and increasing fall risk. It also requires the patient to reach forward, reducing the mechanical advantage of the upper extremities for support. The walker should remain close enough to maintain an upright posture. Excessive advancement does not reduce upper extremity work; it actually increases it by forcing a less favorable arm position.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Walker Advance Distance Safety" },
  { id: "pta-b35-051", stem: "A PTA is treating a patient in a skilled nursing facility. The patient's roommate coughs and asks the PTA to hand them their water cup. The PTA should:", options: ["Hand the water cup to the roommate since it is a simple request that takes minimal time", "Politely decline and direct the roommate to use the call bell for nursing staff, as the PTA should not provide care or services to patients not on their caseload due to liability, scope of practice, and documentation concerns", "Assess the roommate's coughing and perform a pulmonary evaluation", "Provide the water but document it in the roommate's medical record"], correctIndex: 1, rationale: "The PTA should not provide care or services to patients not assigned to their caseload. Even a simple request like handing water carries liability risks: the patient may have dysphagia requiring thickened liquids, may be NPO (nothing by mouth), or may have fluid restrictions. The PTA is not aware of the roommate's medical orders and could inadvertently cause harm. The appropriate response is to direct the roommate to use the call bell. Performing a pulmonary evaluation is outside the PTA's assigned caseload. Documenting in another patient's chart without an order is inappropriate.", difficulty: 2, category: "Patient Safety & Body Mechanics", topic: "Non-Caseload Patient Request Handling" },
  { id: "pta-b35-052", stem: "A PTA is transporting a patient in a wheelchair down a steep ramp. The safest technique is:", options: ["Push the wheelchair forward down the ramp at normal speed with the patient facing downhill", "Turn the wheelchair around and back down the ramp slowly, with the PTA positioned behind (uphill from) the wheelchair, using their body weight to control the descent speed", "Allow the patient to wheel themselves down the ramp independently regardless of the incline grade", "Tilt the wheelchair backward on its rear wheels and slide down the ramp on the rear wheels only"], correctIndex: 1, rationale: "Backing a wheelchair down a steep ramp is the safest technique. The PTA positions themselves behind (uphill from) the wheelchair, using body weight and controlled stepping to manage descent speed. This prevents the wheelchair from gaining dangerous speed and allows the PTA to stop the chair if needed. Pushing forward down a steep ramp risks losing control as gravity accelerates the chair. Independent wheeling on steep ramps risks runaway acceleration. Tilting on rear wheels only is unstable on a ramp and risks tipping. The PTA should keep the wheelchair tilted slightly back during descent for additional control.", difficulty: 1, category: "Patient Safety & Body Mechanics", topic: "Wheelchair Ramp Descent Technique" },
  { id: "pta-b35-053", stem: "A PTA is treating a patient who has a chest tube connected to a water seal drainage system. During ambulation, the PTA notices the water in the water seal chamber is not fluctuating (tidaling) with respiration. This finding suggests:", options: ["Normal chest tube function with complete lung re-expansion", "The chest tube may be occluded by a clot or kink in the tubing, or the lung has fully re-expanded and the tube is no longer needed; the PTA should check the tubing for kinks and notify the nursing staff and supervising PT immediately", "The water seal chamber needs more water added", "The suction should be increased to the maximum setting"], correctIndex: 1, rationale: "Absence of tidaling (water level fluctuation with respiration) in the water seal chamber can indicate: tube occlusion (kink, clot, or dependent loop), full lung re-expansion (tube no longer functional), or system disconnection. The PTA should first check for visible kinks in the tubing and then notify nursing staff and the PT immediately, as a blocked tube can cause tension pneumothorax. Adding water does not address the underlying problem. Increasing suction without identifying the cause of absent tidaling is inappropriate. The PTA should never clamp the chest tube without a physician order.", difficulty: 3, category: "Patient Safety & Body Mechanics", topic: "Chest Tube Tidaling Assessment" },
  { id: "pta-b35-054", stem: "A PTA is using a gait belt during ambulation training with a patient who has a recent T12 vertebral compression fracture and is wearing a thoracolumbosacral orthosis (TLSO). The gait belt should be positioned:", options: ["Directly over the TLSO brace at the waist level", "Around the patient's hips below the TLSO brace to avoid compressing the brace against the fracture site and compromising the orthotic support", "Around the patient's chest above the brace for maximum control", "Gait belts are contraindicated with any spinal orthosis"], correctIndex: 1, rationale: "When a patient is wearing a TLSO, the gait belt should be placed around the hips below the brace. Placing it directly over the TLSO can compress the brace against the fracture site, cause pain, and compromise the orthotic support. Placing it above the brace around the chest restricts respiration and does not provide adequate control at the center of gravity. Gait belts are not contraindicated with spinal orthoses; they just need appropriate positioning. The PTA should ensure the belt does not interfere with the brace's function while still providing adequate fall prevention support.", difficulty: 2, category: "Patient Safety & Body Mechanics", topic: "Gait Belt Positioning with TLSO" },
  { id: "pta-b35-055", stem: "A PTA is performing manual muscle testing (MMT) of the middle deltoid in a patient with shoulder weakness. To test a grade 3 (Fair) muscle, the patient should:", options: ["Hold the arm in 90 degrees of abduction against maximum resistance applied by the PTA", "Actively abduct the shoulder to 90 degrees against gravity (seated position, arm at side, lift arm to horizontal) through full ROM without any manual resistance", "Abduct the shoulder through full ROM in a gravity-eliminated position (side-lying)", "Demonstrate a palpable muscle contraction without any visible joint movement"], correctIndex: 1, rationale: "MMT grade 3 (Fair) requires the patient to complete full range of motion against gravity without additional manual resistance. For the middle deltoid, this means actively abducting the shoulder from 0 to 90 degrees in a seated or standing position (gravity acts as resistance). Grade 5 (Normal) involves full ROM against maximum resistance. Grade 2 (Poor) is full ROM in a gravity-eliminated position. Grade 1 (Trace) is a palpable contraction without visible movement. Understanding the grading criteria ensures accurate and reliable strength documentation.", difficulty: 1, category: "Data Collection & Measurement", topic: "Manual Muscle Testing Deltoid Grade 3" },
  { id: "pta-b35-056", stem: "A PTA is measuring a patient's knee flexion ROM using a goniometer. The proper goniometer alignment for measuring knee flexion is:", options: ["Fulcrum over the medial epicondyle of the femur, stationary arm aligned with the lateral midline of the femur toward the greater trochanter, moving arm aligned with the lateral midline of the fibula toward the lateral malleolus", "Fulcrum over the lateral epicondyle of the femur, stationary arm aligned with the lateral midline of the femur toward the greater trochanter, moving arm aligned with the lateral midline of the fibula toward the lateral malleolus", "Fulcrum over the patella, both arms aligned parallel to the tibial shaft", "Fulcrum over the ankle joint with arms pointing toward the knee and toes"], correctIndex: 1, rationale: "Standard goniometric alignment for knee flexion: fulcrum (axis) over the lateral epicondyle of the femur, stationary arm aligned with the lateral midline of the femur pointing toward the greater trochanter, and moving arm aligned with the lateral midline of the fibula pointing toward the lateral malleolus. The medial epicondyle is incorrect as the standard landmark is the lateral epicondyle. The patella is not the axis of rotation. The ankle is not the axis for knee flexion measurement. Consistent landmark identification ensures reliable and reproducible measurements.", difficulty: 1, category: "Data Collection & Measurement", topic: "Goniometry Knee Flexion Alignment" },
  { id: "pta-b35-057", stem: "A PTA is administering the Berg Balance Scale (BBS) to a 78-year-old patient following a hip fracture. The patient scores 38 out of 56 on the BBS. This score indicates:", options: ["The patient has excellent balance and is safe for independent ambulation without an assistive device", "The patient is at moderate fall risk, as scores of 41-56 indicate low fall risk, 21-40 indicate moderate fall risk, and 0-20 indicate high fall risk, suggesting the need for an assistive device and continued balance training", "The patient has the maximum possible fall risk and requires a wheelchair at all times", "The BBS score of 38 has no clinical significance for fall risk prediction"], correctIndex: 1, rationale: "The Berg Balance Scale scores range from 0-56. A score of 38 falls in the moderate fall risk category (21-40), indicating the patient has balance deficits that increase fall risk but still has functional balance abilities. Scores of 41-56 suggest lower fall risk, while scores of 0-20 indicate high fall risk. A score of 38 does not indicate excellent balance or maximum fall risk. The BBS is a well-validated and clinically significant tool for fall risk assessment. This score suggests the patient would benefit from an assistive device and continued balance intervention.", difficulty: 2, category: "Data Collection & Measurement", topic: "Berg Balance Scale Score Interpretation" },
  { id: "pta-b35-058", stem: "A PTA is performing a Timed Up and Go (TUG) test on a 72-year-old patient with Parkinson's disease. The patient completes the test in 16 seconds. This result indicates:", options: ["Normal mobility with no fall risk", "The patient is at increased risk for falls, as TUG times greater than 13.5 seconds in community-dwelling older adults indicate increased fall risk and the need for further balance and mobility assessment", "The patient should be immediately admitted to an inpatient rehabilitation facility", "The TUG test is not valid for patients with Parkinson's disease"], correctIndex: 1, rationale: "The Timed Up and Go test measures functional mobility. A time of greater than 13.5 seconds in community-dwelling older adults is associated with increased fall risk. The patient's time of 16 seconds exceeds this threshold, indicating elevated fall risk requiring further assessment and intervention. A time under 10 seconds is considered normal. The result does not automatically warrant inpatient admission. The TUG is valid and commonly used for patients with Parkinson's disease and is included in evidence-based guidelines for this population. Results should be interpreted alongside other clinical findings.", difficulty: 2, category: "Data Collection & Measurement", topic: "Timed Up and Go Fall Risk Interpretation" },
  { id: "pta-b35-059", stem: "A PTA is assessing a patient's deep tendon reflexes and records a finding of '3+' for the biceps reflex. This grade indicates:", options: ["A normal reflex response", "An absent reflex response", "A hyperactive (brisker than normal) reflex without clonus, which may suggest an upper motor neuron lesion", "A reflex that was only elicited with reinforcement techniques"], correctIndex: 2, rationale: "Deep tendon reflex grading: 0 = absent, 1+ = diminished (may require reinforcement), 2+ = normal, 3+ = hyperactive without clonus, 4+ = hyperactive with clonus. A 3+ reflex is brisker than normal and may indicate an upper motor neuron lesion affecting the corticospinal tract's inhibitory influence on spinal reflexes. Normal is 2+. Absent is 0. Reflexes requiring reinforcement (Jendrassik maneuver) are graded 1+. The PTA should document and communicate hyperactive reflexes to the supervising PT as they may indicate neurological pathology requiring further evaluation.", difficulty: 2, category: "Data Collection & Measurement", topic: "Deep Tendon Reflex Grading 3+" },
  { id: "pta-b35-060", stem: "A PTA is measuring a patient's ankle dorsiflexion ROM and obtains a measurement of 5 degrees with the knee extended and 15 degrees with the knee flexed. This difference MOST likely indicates:", options: ["Tightness of the gastrocnemius muscle, which crosses both the knee and ankle joints; knee flexion slackens the gastrocnemius, allowing greater dorsiflexion, while knee extension tightens it across both joints", "Tightness of the soleus muscle specifically", "An ankle joint capsular restriction that is position-independent", "An error in measurement technique requiring reassessment"], correctIndex: 0, rationale: "The gastrocnemius is a two-joint muscle crossing the knee (origin) and ankle (insertion). With the knee extended, the gastrocnemius is stretched across both joints, limiting dorsiflexion. Knee flexion slackens the gastrocnemius at the knee, isolating ankle dorsiflexion to the soleus (which only crosses the ankle). The 10-degree difference with knee position change indicates gastrocnemius tightness, not soleus. A joint capsular restriction would limit dorsiflexion equally regardless of knee position. The difference between positions is clinically meaningful and indicates a specific muscle restriction.", difficulty: 2, category: "Data Collection & Measurement", topic: "Gastrocnemius vs Soleus Dorsiflexion Testing" },
  { id: "pta-b35-061", stem: "A PTA is using the Visual Analog Scale (VAS) to measure a patient's pain intensity. The patient marks the VAS line at 72 mm from the left anchor. Which interpretation is correct?", options: ["The patient's pain is rated at 72 out of 100, indicating moderate-to-severe pain intensity, and the VAS has a minimally clinically important difference (MCID) of approximately 13 mm for meaningful change", "The score of 72 mm is meaningless without additional pain questionnaires", "A VAS score can only be recorded as mild, moderate, or severe", "The VAS measurement of 72 mm indicates the patient has no significant pain"], correctIndex: 0, rationale: "The VAS is a 100-mm line where 0 = no pain and 100 = worst imaginable pain. The patient marks their perceived pain level, and the distance from the left anchor is measured in millimeters. A score of 72/100 indicates moderate-to-severe pain. The MCID for the VAS is approximately 13 mm, meaning changes of at least 13 mm represent clinically meaningful improvement or worsening. VAS scores are continuous numerical data, not categorical. A 72 mm score clearly indicates significant pain. The VAS is a valid standalone pain measurement tool, though it can be supplemented with other assessments.", difficulty: 2, category: "Data Collection & Measurement", topic: "Visual Analog Scale Interpretation MCID" },
  { id: "pta-b35-062", stem: "A PTA is performing a sensory assessment on a patient with suspected peripheral neuropathy. When testing light touch using a Semmes-Weinstein monofilament, the 5.07 (10-gram) monofilament is the threshold used specifically to assess:", options: ["Normal light touch sensation in the upper extremities", "Protective sensation in the feet, where inability to detect the 5.07 monofilament indicates loss of protective sensation and significantly increased risk of foot ulceration in diabetic patients", "Deep pressure pain threshold", "Two-point discrimination for fine motor function"], correctIndex: 1, rationale: "The 5.07 (10-gram) Semmes-Weinstein monofilament is the gold standard for assessing protective sensation in the feet. Inability to detect this monofilament indicates loss of protective sensation, which dramatically increases the risk of undetected foot injuries and ulceration, particularly in diabetic patients. It does not assess normal light touch (which uses lighter monofilaments), deep pressure pain, or two-point discrimination (which uses a two-point discriminator or caliper). Annual monofilament testing is recommended for all diabetic patients to identify those at risk for foot complications.", difficulty: 2, category: "Data Collection & Measurement", topic: "Semmes-Weinstein Monofilament Protective Sensation" },
  { id: "pta-b35-063", stem: "A PTA is performing the Special Test for shoulder impingement known as the Neer test. A positive result is indicated by:", options: ["Pain reproduced when the examiner passively flexes the patient's arm overhead with the scapula stabilized, compressing the supraspinatus tendon against the anterior acromion", "Clicking or popping in the shoulder with active abduction", "Weakness during resisted external rotation at 0 degrees of abduction", "Numbness and tingling radiating down the arm to the fingers"], correctIndex: 0, rationale: "The Neer impingement test involves the examiner stabilizing the scapula with one hand and passively flexing the shoulder overhead with the other hand. A positive test reproduces the patient's pain as the supraspinatus tendon and subacromial bursa are compressed against the anterior-inferior acromion. Clicking suggests labral pathology. Weakness with resisted external rotation suggests infraspinatus pathology. Numbness and tingling suggest neural compression (thoracic outlet or cervical radiculopathy), not impingement. The Neer test is a screening test and should be combined with other tests for a comprehensive assessment.", difficulty: 1, category: "Data Collection & Measurement", topic: "Neer Impingement Test Interpretation" },
  { id: "pta-b35-064", stem: "A PTA is educating a patient with newly diagnosed type 2 diabetes about an exercise program. The patient asks when they should NOT exercise. The PTA should advise the patient to avoid exercise when:", options: ["Blood glucose is within the normal range of 100-180 mg/dL", "Blood glucose is above 300 mg/dL or above 250 mg/dL with ketones present, as exercise in a hyperglycemic state with insulin deficiency can worsen hyperglycemia and precipitate diabetic ketoacidosis", "Blood glucose is exactly 150 mg/dL, which is considered dangerous for exercise", "The patient has eaten a small snack within the last 2 hours"], correctIndex: 1, rationale: "Exercise is contraindicated when blood glucose exceeds 300 mg/dL or exceeds 250 mg/dL with ketones present. In these conditions, insulin deficiency prevents glucose utilization, and exercise stimulates hepatic glucose release and counterregulatory hormones, worsening hyperglycemia and potentially precipitating DKA. Blood glucose of 100-180 mg/dL is an appropriate range for exercise. A glucose of 150 mg/dL is well within the safe range. Eating a snack before exercise is actually recommended to prevent hypoglycemia. The PTA should also educate about hypoglycemia precautions for glucose below 70 mg/dL.", difficulty: 2, category: "Patient Education & Home Programs", topic: "Diabetic Exercise Blood Glucose Thresholds" },
  { id: "pta-b35-065", stem: "A PTA is developing a home exercise program (HEP) for a 75-year-old patient with balance deficits who lives alone. The patient has a history of two falls in the past 6 months. Which instruction is MOST important for safety during the home balance exercise program?", options: ["Perform all balance exercises while standing in the middle of a large open room without any nearby support", "Perform standing balance exercises in a corner of a room or near a sturdy countertop for safety, never practice balance exercises when home alone without a way to call for help, and start with the easiest exercises first", "Only perform balance exercises at the physical therapy clinic, never at home", "Perform the most challenging balance exercises first to get them done while energy is highest"], correctIndex: 1, rationale: "Home balance exercises for patients at fall risk require safety modifications: exercising near a sturdy support (counter, corner) provides emergency handholds, having a way to call for help (phone nearby or medical alert device) ensures assistance if a fall occurs, and starting with easier exercises allows warm-up before challenging balance. Exercising without nearby support increases fall risk. Limiting balance exercises to clinic visits reduces practice frequency and slows improvement. Performing the most challenging exercises first without warm-up increases fall risk when the patient is not yet engaged in the activity.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Home Balance Exercise Safety Instructions" },
  { id: "pta-b35-066", stem: "A PTA is educating a patient who had a total knee replacement about cryotherapy use at home. The patient asks how often to ice the knee. The PTA should recommend:", options: ["Ice continuously for 24 hours per day for the first 2 weeks post-surgery", "Apply ice for 15-20 minutes every 1-2 hours during the first 48-72 hours, then 3-4 times daily as needed for swelling and pain management, always using a barrier between the ice and skin", "Ice only once per week for 5 minutes to avoid tissue damage", "Never use ice at home after surgery as it is only safe under clinical supervision"], correctIndex: 1, rationale: "Post-TKA cryotherapy guidelines: 15-20 minutes per application with a barrier, every 1-2 hours during the acute phase (48-72 hours), then reducing to 3-4 times daily or as needed. Continuous icing risks frostbite and tissue necrosis. Once weekly for 5 minutes is insufficient for therapeutic benefit. Home cryotherapy is safe and effective when proper instructions are followed. A barrier (towel or pillowcase) between ice and skin prevents cryotherapy burns. The PTA should also instruct the patient to elevate the leg during icing and to check skin after each application.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Post-TKA Home Cryotherapy Instructions" },
  { id: "pta-b35-067", stem: "A PTA is providing education to a patient with chronic heart failure (CHF) about exercise precautions for their home program. The patient should be instructed to STOP exercising and contact their healthcare provider if they experience:", options: ["Mild muscle soreness the day after exercising", "A weight gain of more than 2-3 pounds in a 24-hour period, new or worsening shortness of breath at rest, or chest pain during exercise, as these may indicate fluid retention or cardiac decompensation", "A slight increase in heart rate during moderate exercise that returns to baseline within 5 minutes of rest", "Mild perspiration during exercise in warm weather"], correctIndex: 1, rationale: "CHF patients should stop exercise and contact their provider for: rapid weight gain (more than 2-3 pounds in 24 hours indicating fluid retention), new or worsening dyspnea at rest (suggesting decompensation), and chest pain during exercise (possible ischemia). Mild muscle soreness is a normal exercise response. Heart rate increase during exercise with appropriate recovery is expected. Mild perspiration is a normal thermoregulatory response. Daily weight monitoring is critical for CHF patients to detect early fluid retention before severe decompensation occurs.", difficulty: 2, category: "Patient Education & Home Programs", topic: "CHF Exercise Warning Signs" },
  { id: "pta-b35-068", stem: "A PTA is teaching a patient with a new lumbar fusion how to perform a log-roll technique for getting out of bed. The correct sequence for the log-roll is:", options: ["Sit up directly from a supine position by performing a sit-up motion", "Roll onto the side as a unit (keeping the spine aligned without twisting) by bending the knees and using the arms to push, then lower the legs off the bed while pushing up with the arms to achieve a sitting position at the edge of the bed", "Twist the upper body first, then swing the legs over the edge while lying supine", "Slide off the foot of the bed feet-first while keeping the back flat on the mattress"], correctIndex: 1, rationale: "The log-roll technique maintains spinal alignment during bed mobility, critical after lumbar fusion to protect the surgical site. The patient rolls onto their side as a unit (shoulders and hips move together without twisting), then lowers the legs off the bed edge while pushing up with the arms. This avoids spinal flexion, extension, and rotation stresses on the fusion. Sitting up directly involves spinal flexion stress. Twisting the upper body creates rotational forces on the fusion. Sliding off the bed foot-first involves uncontrolled spinal positioning. The log-roll should be practiced before surgery when possible.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Log-Roll Technique Lumbar Fusion" },
  { id: "pta-b35-069", stem: "A PTA is providing patient education about osteoporosis management to a 65-year-old postmenopausal woman with a T-score of -2.8 at the lumbar spine. Which exercise recommendation is MOST appropriate?", options: ["High-impact jumping and heavy spinal flexion exercises like sit-ups to maximize bone loading", "Weight-bearing exercises such as walking and low-impact aerobics combined with resistance training, while avoiding spinal flexion exercises (sit-ups, toe touches) that increase vertebral compression fracture risk in osteoporotic spines", "Complete avoidance of all exercise due to fracture risk", "Non-weight-bearing exercises exclusively, such as swimming and recumbent cycling"], correctIndex: 1, rationale: "For osteoporosis (T-score ≤ -2.5), weight-bearing exercise and resistance training stimulate osteoblast activity and bone remodeling. However, spinal flexion exercises (sit-ups, toe touches, crunches) create anterior vertebral compression forces that significantly increase fracture risk in osteoporotic spines. High-impact jumping may also exceed bone tolerance in severe osteoporosis. Complete exercise avoidance accelerates bone loss. Non-weight-bearing exercises alone do not provide the mechanical loading stimulus needed for bone formation. The combination of weight-bearing and resistance exercise with avoidance of spinal flexion is the evidence-based approach.", difficulty: 2, category: "Patient Education & Home Programs", topic: "Osteoporosis Exercise Precautions" },
  { id: "pta-b35-070", stem: "A PTA is treating a patient with chronic low back pain who demonstrates poor adherence to the home exercise program. The patient states they understand the exercises but cannot find time to do them. The MOST effective strategy to improve adherence is:", options: ["Prescribe additional exercises to increase the program's effectiveness", "Simplify the program to 3-4 key exercises, help the patient identify specific times to integrate exercises into their daily routine (such as before morning shower), and use motivational interviewing techniques to explore barriers and build self-efficacy", "Tell the patient their pain will get worse if they do not comply with the full program", "Discharge the patient from therapy for non-compliance"], correctIndex: 1, rationale: "Research on HEP adherence shows that simpler programs with fewer exercises have better compliance. Helping the patient link exercises to existing daily routines (habit stacking) creates behavioral cues that improve follow-through. Motivational interviewing explores barriers without judgment and builds intrinsic motivation. Adding more exercises increases complexity and worsens adherence. Fear-based messaging (pain will worsen) can increase anxiety and reduce self-efficacy. Discharging for non-compliance is premature without first attempting adherence strategies. Patient-centered collaborative problem-solving is the most effective approach.", difficulty: 2, category: "Patient Education & Home Programs", topic: "HEP Adherence Improvement Strategies" },
  { id: "pta-b35-071", stem: "A PTA is educating a patient with a new above-knee amputation about residual limb care and wrapping. The primary purpose of elastic bandage wrapping of the residual limb is:", options: ["To prevent infection at the surgical incision site", "To shape the residual limb into a conical form for optimal prosthetic socket fit and to control edema through distal-to-proximal gradient compression", "To maintain the limb in hip flexion for patient comfort", "To completely restrict all blood flow to promote wound healing"], correctIndex: 1, rationale: "Elastic bandage wrapping serves two primary purposes: shaping the residual limb into a conical (tapered) form that fits properly into a prosthetic socket, and controlling post-surgical edema through gradient compression (tighter distally, looser proximally). Infection prevention requires wound care, not wrapping. Wrapping should actually encourage hip extension (not flexion) to prevent hip flexion contracture, which interferes with prosthetic gait. The wrapping should never completely restrict blood flow, as this would cause tissue ischemia. The figure-of-eight wrapping pattern is preferred over circular wrapping to avoid a tourniquet effect.", difficulty: 1, category: "Patient Education & Home Programs", topic: "Above-Knee Amputation Limb Wrapping" },
  { id: "pta-b35-072", stem: "A PTA is writing a SOAP note for a patient with a shoulder injury. In the Objective section, the PTA documents: 'Shoulder AROM flexion 145°, abduction 130°, ER 65°. MMT shoulder flexion 4/5, abduction 3+/5. Tenderness palpated over supraspinatus insertion.' Which element does NOT belong in the Objective section?", options: ["Shoulder AROM measurements", "MMT grades", "The statement about tenderness, as all listed elements are appropriate objective findings that are measurable and reproducible", "None of these; all elements belong in the Objective section"], correctIndex: 3, rationale: "All listed elements are appropriate for the Objective section of a SOAP note. Active ROM measurements are quantifiable objective data. MMT grades are standardized objective strength measurements. Tenderness to palpation is a clinical finding identified through the PTA's examination. The Objective section includes all measurable, observable, and reproducible findings from the session: ROM, strength, functional measures, gait observations, and clinical test results. Subjective information (patient reports, pain levels, feelings) goes in the Subjective section. Assessment interpretations go in the Assessment section.", difficulty: 1, category: "Documentation & Communication", topic: "SOAP Note Objective Section Content" },
  { id: "pta-b35-073", stem: "A PTA receives a verbal order from a physician to change a patient's exercise program to include pool therapy. The PTA should:", options: ["Implement the pool therapy program immediately as directed by the physician since they have the highest authority", "Inform the physician that any changes to the physical therapy plan of care must go through the supervising physical therapist, and then communicate the physician's request to the supervising PT for evaluation and plan of care modification", "Refuse the order and continue the current program without informing anyone", "Have the patient sign a consent form and begin pool therapy independently"], correctIndex: 1, rationale: "The physical therapy plan of care is established and modified by the supervising PT, not by physician verbal orders to the PTA. The PTA's scope requires that treatment changes go through the supervising PT. The PTA should respectfully inform the physician of the proper communication channel and then immediately relay the request to the PT. Implementing without PT involvement violates scope of practice and supervisory requirements. Refusing without communication fails to advocate for the patient. Beginning pool therapy independently without PT direction exceeds PTA scope regardless of consent.", difficulty: 2, category: "Documentation & Communication", topic: "Physician Order to PTA Chain of Command" },
  { id: "pta-b35-074", stem: "A PTA is treating a patient who states, 'I don't think physical therapy is working. I want to stop coming.' The PTA's MOST appropriate response is:", options: ["Tell the patient they must continue therapy because the doctor ordered it", "Acknowledge the patient's concerns, explore specific reasons for dissatisfaction, document the patient's statements, and inform the supervising PT so the plan of care can be reassessed and patient concerns can be addressed through collaborative goal setting", "Agree with the patient and discharge them from therapy immediately", "Ignore the comment and continue with the planned treatment session"], correctIndex: 1, rationale: "Patient concerns about treatment effectiveness should be acknowledged and explored. Active listening and empathy validate the patient's experience. Documenting the patient's statements and informing the PT allows reassessment of the plan of care, goal modification, or alternative approaches. Telling the patient they must continue is paternalistic and ignores patient autonomy. Discharging without PT involvement and appropriate assessment is premature. Ignoring the concern damages the therapeutic relationship and may result in the patient not returning. Patient satisfaction and engagement are critical for outcomes.", difficulty: 2, category: "Documentation & Communication", topic: "Patient Dissatisfaction Response" },
  { id: "pta-b35-075", stem: "A PTA is documenting a patient encounter and needs to correct an error in the medical record. The appropriate method for correcting a handwritten documentation error is:", options: ["Use correction fluid (white-out) to completely cover the error and rewrite the correct information", "Draw a single line through the error so it remains readable, write the correction above or next to it, and initial and date the correction", "Remove the page containing the error and rewrite the entire note on a new page", "Leave the error and add a separate note explaining the mistake at a later date"], correctIndex: 1, rationale: "Proper medical record correction requires drawing a single line through the error (maintaining readability of the original entry), writing the correct information nearby, and initialing and dating the correction. This maintains the integrity of the medical record as a legal document. White-out conceals the original entry, which is considered tampering. Removing pages constitutes destruction of medical records. Leaving uncorrected errors and adding separate notes creates confusion and may constitute falsification. The original entry must remain visible to demonstrate transparency and maintain the chronological integrity of the record.", difficulty: 1, category: "Documentation & Communication", topic: "Medical Record Error Correction" },
  { id: "pta-b35-076", stem: "A PTA is treating a patient when a family member enters the treatment area and asks about the patient's diagnosis and prognosis. The PTA should:", options: ["Provide a detailed explanation of the diagnosis and treatment plan to the family member since they appear concerned", "Politely explain that patient health information is protected by HIPAA and that the family member should discuss the patient's condition with the patient directly or obtain the patient's written authorization before the PTA can share any information", "Ignore the family member and continue treating the patient without acknowledging the question", "Tell the family member to call the front desk for a copy of the patient's records"], correctIndex: 1, rationale: "HIPAA protects patient health information (PHI). The PTA cannot share diagnosis, prognosis, or treatment details with anyone without the patient's explicit written authorization, even family members. The PTA should politely explain confidentiality requirements and redirect the family member to speak with the patient. Providing detailed information violates HIPAA. Ignoring the family member is unprofessional. Directing them to obtain records bypasses the patient's right to authorize disclosure. If the patient is present and provides verbal consent during the encounter, the PTA may share information with the family member at that time.", difficulty: 1, category: "Documentation & Communication", topic: "HIPAA Family Member Information Request" },
  { id: "pta-b35-077", stem: "A PTA is delegating tasks to a physical therapy aide. Which of the following tasks is within the aide's scope of responsibilities under PTA supervision?", options: ["Performing manual muscle testing on a patient with a new injury", "Preparing the treatment area, setting up equipment, assisting with patient transport to the treatment area, and performing non-clinical housekeeping tasks under the direct supervision of the PTA", "Independently progressing a patient's exercise program based on the patient's reported improvement", "Interpreting goniometric measurements and modifying the treatment plan accordingly"], correctIndex: 1, rationale: "Physical therapy aides perform non-clinical support tasks: preparing treatment areas, setting up equipment, transporting patients, and housekeeping duties. All aide activities require direct supervision (PTA must be present in the facility and available). MMT is a skilled assessment that requires PTA or PT training. Independently progressing exercise programs requires clinical judgment beyond aide scope. Interpreting measurements and modifying treatment plans requires clinical expertise. The PTA retains responsibility for all clinical decisions and cannot delegate skilled interventions or clinical assessments to aides.", difficulty: 2, category: "Documentation & Communication", topic: "Physical Therapy Aide Task Delegation" },
  { id: "pta-b35-078", stem: "A PTA is documenting a treatment session and writes in the Assessment section: 'Patient continues to make progress toward goals. Knee flexion ROM has improved 10° since last visit. Patient would benefit from continued PT 2x/week.' A problem with this documentation is:", options: ["Including ROM improvement data is inappropriate for the Assessment section", "The statement about treatment frequency recommendation exceeds PTA documentation scope, as recommending frequency of care modifications constitutes a change to the plan of care, which is within the PT's scope of practice and responsibility", "The Assessment section should never contain professional judgment or opinions", "There are no problems with this documentation"], correctIndex: 1, rationale: "The PTA can document progress observations and clinical reasoning in the Assessment section. However, recommending specific treatment frequency changes (2x/week) constitutes modifying the plan of care, which is the supervising PT's responsibility. The PTA should document findings that support the need for continued services and communicate their observations to the PT for plan of care decisions. ROM improvement data is appropriate in the Assessment as clinical interpretation. Professional judgment about progress is appropriate for PTA documentation. The frequency recommendation is the specific issue exceeding PTA documentation scope.", difficulty: 3, category: "Documentation & Communication", topic: "PTA Assessment Documentation Scope" },
  { id: "pta-b35-079", stem: "A PTA receives a subpoena to provide testimony in a legal case regarding a patient they treated. The PTA should:", options: ["Immediately call the patient's attorney and provide all requested information over the phone", "Notify their supervisor and the facility's legal department or risk management before responding, and not release any information or provide testimony without proper legal guidance and authorization", "Shred the patient's medical records to protect their privacy", "Ignore the subpoena since patient information is protected by HIPAA"], correctIndex: 1, rationale: "Upon receiving a subpoena, the PTA must immediately notify their supervisor and the facility's legal/risk management department. Legal counsel will guide the response, determine what information can be released, and ensure proper procedures are followed. Calling the patient's attorney without legal guidance may violate facility policies and HIPAA. Shredding records constitutes destruction of evidence and is illegal. Ignoring a subpoena can result in contempt of court charges. While HIPAA protects patient information, subpoenas have specific legal requirements that must be navigated through proper legal channels.", difficulty: 3, category: "Documentation & Communication", topic: "Subpoena Response Legal Protocol" },
  { id: "pta-b35-080", stem: "A PTA is documenting a patient's functional progress and writes: 'Patient ambulated 150 feet with a standard walker on level surfaces with standby assist x1 for safety. Gait speed measured at 0.8 m/s. Patient required two seated rest breaks during the distance.' This documentation demonstrates which important documentation principle?", options: ["The note is too detailed and should simply state 'patient walked with a walker'", "The note demonstrates appropriate objective documentation by including specific measurable parameters: distance (150 feet), assistive device (standard walker), level of assistance (standby assist x1), surface type (level), gait speed (0.8 m/s), and endurance limitations (two rest breaks)", "The note should only include the gait speed measurement without any other details", "The note is missing the patient's subjective pain report, which should be included in the Objective section"], correctIndex: 1, rationale: "This documentation exemplifies best practices by including all measurable parameters that track functional progress: specific distance, assistive device type, assistance level using standardized terminology, surface type, quantitative gait speed, and endurance information. These details allow comparison between sessions and demonstrate medical necessity. Simply stating 'patient walked with a walker' lacks specificity for insurance justification and progress tracking. Gait speed alone misses functional context. Pain reports belong in the Subjective section, not the Objective section. Comprehensive functional documentation supports reimbursement and demonstrates skilled care necessity.", difficulty: 2, category: "Documentation & Communication", topic: "Functional Ambulation Documentation Standards" }
];
